import React from 'react';

interface AssetToolbarProps {
  selectedCount: number;
  showAddNew: boolean;
  selectedProductTypeName: string;
  onAddNew: () => void;
  onDeleteSelected: () => void;
  onClearFilters: () => void;
  onSelectColumns: () => void;
}

const AssetToolbar: React.FC<AssetToolbarProps> = ({
  selectedCount,
  showAddNew,
  selectedProductTypeName,
  onAddNew,
  onDeleteSelected,
  onClearFilters,
  onSelectColumns,
}) => {
  return (
    <div className="rounded-lg border border-slate-200 bg-white px-5 py-4 shadow-sm">
      <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
        <div className="min-w-0 text-sm font-semibold text-slate-900">
          <span className="block truncate">{selectedProductTypeName || 'Assets'}</span>
        </div>
        <div className="flex flex-wrap items-center gap-2 lg:flex-nowrap lg:justify-end">
          {showAddNew && (
            <button
              type="button"
              onClick={onAddNew}
              className="inline-flex h-9 shrink-0 items-center gap-2 rounded-md bg-blue-600 px-3.5 text-sm font-semibold text-white shadow-sm transition hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <svg className="h-4 w-4" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                <path d="M8 3V13M3 8H13" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" />
              </svg>
              Add new
            </button>
          )}
          <button
            type="button"
            onClick={onDeleteSelected}
            className="inline-flex h-9 shrink-0 items-center gap-2 rounded-md border border-slate-300 bg-white px-3.5 text-sm font-semibold text-slate-700 transition hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <svg className="h-4 w-4" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
              <path d="M3 4H13M6 4V3H10V4M5 6V13H11V6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
            Delete{selectedCount > 0 ? ` (${selectedCount})` : ' (selected)'}
          </button>
        <button
          type="button"
          onClick={onClearFilters}
          className="inline-flex h-9 shrink-0 items-center rounded-md border border-slate-300 bg-white px-3.5 text-sm text-slate-700 transition hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          Clear All Filters
        </button>
        <button
          type="button"
          onClick={onSelectColumns}
          className="inline-flex h-9 shrink-0 items-center rounded-md border border-slate-300 bg-white px-3.5 text-sm text-slate-700 transition hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          &#9654; Select Columns
        </button>
        </div>
      </div>
    </div>
  );
};

export default AssetToolbar;
